// // This module compares two 2-bit binary inputs and outputs 1 if the first input is less than or equal to the second input.
module comparator_2bit(A, B, A_gt_B);
input [1:0] A, B;
output reg A_gt_B;

always @(*) begin
    if (A > B)
        A_gt_B = 1'b1;
    else
        A_gt_B = 1'b0;
end

endmodule
